-- Groepswedstrijden waarvan de (juiste) kickoff al voorbij is, maar waarvoor
-- nog GEEN resultaat in de results-tabel staat (sync mogelijk mislukt).
WITH correct(match_id, correct_kickoff, wedstrijd) AS (
  SELECT json_extract(j.value,'$.id'), CAST(json_extract(j.value,'$.ko') AS INTEGER), json_extract(j.value,'$.w')
  FROM json_each('[{"id":"m1","ko":1781204400000,"w":"Mexico - Zuid-Afrika"},{"id":"m2","ko":1781229600000,"w":"Zuid-Korea - Tsjechië"},{"id":"m3","ko":1781290800000,"w":"Canada - Bosnië"},{"id":"m4","ko":1781312400000,"w":"VS - Paraguay"},{"id":"m5","ko":1781377200000,"w":"Qatar - Zwitserland"},{"id":"m6","ko":1781388000000,"w":"Brazilië - Marokko"},{"id":"m7","ko":1781398800000,"w":"Haïti - Schotland"},{"id":"m8","ko":1781409600000,"w":"Australië - Turkije"},{"id":"m9","ko":1781456400000,"w":"Duitsland - Curaçao"},{"id":"m10","ko":1781467200000,"w":"Nederland - Japan"},{"id":"m11","ko":1781478000000,"w":"Ivoorkust - Ecuador"},{"id":"m12","ko":1781488800000,"w":"Zweden - Tunesië"},{"id":"m13","ko":1781539200000,"w":"Spanje - Kaapverdië"},{"id":"m14","ko":1781550000000,"w":"België - Egypte"},{"id":"m15","ko":1781560800000,"w":"Saoedi-Arabië - Uruguay"},{"id":"m16","ko":1781571600000,"w":"Iran - Nieuw-Zeeland"},{"id":"m17","ko":1781636400000,"w":"Frankrijk - Senegal"},{"id":"m18","ko":1781647200000,"w":"Irak - Noorwegen"},{"id":"m19","ko":1781658000000,"w":"Argentinië - Algerije"},{"id":"m20","ko":1781668800000,"w":"Oostenrijk - Jordanië"},{"id":"m21","ko":1781715600000,"w":"Portugal - DRC"},{"id":"m22","ko":1781726400000,"w":"Engeland - Kroatië"},{"id":"m23","ko":1781737200000,"w":"Ghana - Panama"},{"id":"m24","ko":1781748000000,"w":"Oezbekistan - Colombia"},{"id":"m25","ko":1781798400000,"w":"Tsjechië - Zuid-Afrika"},{"id":"m26","ko":1781820000000,"w":"Zwitserland - Bosnië"},{"id":"m27","ko":1781827200000,"w":"Canada - Qatar"},{"id":"m28","ko":1781830800000,"w":"Mexico - Zuid-Korea"},{"id":"m29","ko":1781906400000,"w":"Schotland - Marokko"},{"id":"m30","ko":1781895600000,"w":"VS - Australië"},{"id":"m31","ko":1781917200000,"w":"Brazilië - Haïti"},{"id":"m32","ko":1781928000000,"w":"Turkije - Paraguay"},{"id":"m33","ko":1781974800000,"w":"Nederland - Zweden"},{"id":"m34","ko":1781982000000,"w":"Duitsland - Ivoorkust"},{"id":"m35","ko":1782000000000,"w":"Ecuador - Curaçao"},{"id":"m36","ko":1782014400000,"w":"Tunesië - Japan"},{"id":"m37","ko":1782057600000,"w":"Spanje - Saoedi-Arabië"},{"id":"m38","ko":1782079200000,"w":"België - Iran"},{"id":"m39","ko":1782079200000,"w":"Uruguay - Kaapverdië"},{"id":"m40","ko":1782090000000,"w":"Nieuw-Zeeland - Egypte"},{"id":"m41","ko":1782147600000,"w":"Argentinië - Oostenrijk"},{"id":"m42","ko":1782162000000,"w":"Frankrijk - Irak"},{"id":"m43","ko":1782172800000,"w":"Noorwegen - Senegal"},{"id":"m44","ko":1782183600000,"w":"Jordanië - Algerije"},{"id":"m45","ko":1782234000000,"w":"Portugal - Oezbekistan"},{"id":"m46","ko":1782241200000,"w":"Engeland - Ghana"},{"id":"m47","ko":1782255600000,"w":"Panama - Kroatië"},{"id":"m48","ko":1782266400000,"w":"Colombia - DRC"},{"id":"m49","ko":1782338400000,"w":"Zwitserland - Canada"},{"id":"m50","ko":1782338400000,"w":"Bosnië - Qatar"},{"id":"m51","ko":1782338400000,"w":"Schotland - Brazilië"},{"id":"m52","ko":1782338400000,"w":"Marokko - Haïti"},{"id":"m53","ko":1782349200000,"w":"Tsjechië - Mexico"},{"id":"m54","ko":1782349200000,"w":"Zuid-Afrika - Zuid-Korea"},{"id":"m55","ko":1782414000000,"w":"Ecuador - Duitsland"},{"id":"m56","ko":1782414000000,"w":"Curaçao - Ivoorkust"},{"id":"m57","ko":1782428400000,"w":"Japan - Zweden"},{"id":"m58","ko":1782428400000,"w":"Tunesië - Nederland"},{"id":"m59","ko":1782439200000,"w":"Turkije - VS"},{"id":"m60","ko":1782439200000,"w":"Paraguay - Australië"},{"id":"m61","ko":1782500400000,"w":"Noorwegen - Frankrijk"},{"id":"m62","ko":1782500400000,"w":"Senegal - Irak"},{"id":"m63","ko":1782518400000,"w":"Kaapverdië - Saoedi-Arabië"},{"id":"m64","ko":1782518400000,"w":"Uruguay - Spanje"},{"id":"m65","ko":1782529200000,"w":"Egypte - Iran"},{"id":"m66","ko":1782529200000,"w":"Nieuw-Zeeland - België"},{"id":"m67","ko":1782597600000,"w":"Panama - Engeland"},{"id":"m68","ko":1782597600000,"w":"Kroatië - Ghana"},{"id":"m69","ko":1782606600000,"w":"Colombia - Portugal"},{"id":"m70","ko":1782606600000,"w":"DRC - Oezbekistan"},{"id":"m71","ko":1782612000000,"w":"Algerije - Oostenrijk"},{"id":"m72","ko":1782612000000,"w":"Jordanië - Argentinië"}]') AS j
)
SELECT c.match_id, c.wedstrijd, datetime(c.correct_kickoff/1000,'unixepoch') AS kickoff_utc
FROM correct c
LEFT JOIN results r ON r.match_id = c.match_id
WHERE c.correct_kickoff < (strftime('%s','now')*1000)
  AND r.match_id IS NULL
ORDER BY c.correct_kickoff;
